#include <bits/stdc++.h>
using namespace std;
int n,f[50004];
string name[50004];
map<string,int> id;
int father(int x){
    return (f[x]==x?x:f[x]=father(f[x]));
}
void merge(int x,int y){
    int fx=father(x),fy=father(y);
    if(fx!=fy)
        f[fy]=fx;
}
int main(){
    string s;
    int last;
    while(1){
        cin>>s;
        string tmp="";
        if(s=="$")
            break;
        for(int i=1;i<s.size();i++)
            tmp+=s[i];
        if(!id[tmp])
            id[tmp]=++n,f[n]=n,name[n]=tmp;
        if(s[0]=='#'){
            last=id[tmp];
        }else if(s[0]=='+'){
            merge(last,id[tmp]);
        }else{
            cout<<tmp<<' '<<name[father(id[tmp])]<<'\n';
        }
    }
    return 0;
}
